  struct fmt_arg args[] = {FMT_ARG_INT(1), FMT_ARG_CSTRING("foo"),
                           FMT_ARG_DOUBLE(3.14)};
  fmt_format_to(buf, sizeof(buf), "{} {} {:.2f}", args, 3);
  EXPECT_STREQ("1 foo 3.14", buf);
}

